body.script:
promise_test(async () => {
  // We need to determine <body> children.
  if (document.readyState !== 'complete') {
    await new Promise(resolve => window.addEventListener('load', resolve));
  }
  assert_background_color('t1', LIME, 't1: p:nth-last-of-type(3)');
  assert_background_color('t2', LIME, 't2: dt:nth-last-of-type(4)');
  assert_background_color('t3', LIME, 't3: dd:nth-last-of-type(4)');
  assert_background_color('t4', LIME, 't4: dt:nth-last-of-type(1)');
  assert_background_color('t5', LIME, 't5: dd:nth-last-of-type(1)');
}, 'nth-last-of-type');
